SELECT COUNT(DISTINCT school_id) AS unique_schools_offering_tutoring
FROM educational_support
WHERE support_type = 'tutoring';

SELECT school_id, COUNT(support_id) AS number_of_support_services
FROM educational_support
GROUP BY school_id;

SELECT mother_education, COUNT(*) AS mother_count
FROM parents
GROUP BY mother_education;

SELECT school_id, COUNT(activity_id) AS number_of_activities
FROM extracurricular_activities
GROUP BY school_id;

SELECT student_id, SUM(duration) AS total_participation_duration
FROM student_support_logs
GROUP BY student_id;

SELECT support_type, description, support_specialization
FROM educational_support
ORDER BY support_type;
